  "plan": "Kill the current QEMU process and restart with different machine settings - use default CPU, standard VGA, and proper machine type for compatibility with Windows 3.11.",
  "commands": [
    {
      "keystrokes": "kill 1167 2>/dev/null; sleep 1; kill -9 1167 2>/dev/null; sleep 1\n",
      "duration": 3.0
    },
    {
      "keystrokes": "rm -f /tmp/qemu-monitor.sock\n",
      "duration": 0.5
    },
    {
      "keystrokes": "nohup qemu-system-i386 \\\n  -m 16 \\\n  -hda /app/isos/win311.img \\\n  -snapshot \\\n  -vnc :1 \\\n  -monitor unix:/tmp/qemu-monitor.sock,server,nowait \\\n  -vga std \\\n  -net nic,model=ne2k_isa \\\n  -net user \\\n  -boot c \\\n  > /tmp/qemu.log 2>&1 &\n",
      "duration": 2.0
    },
    {
      "keystrokes": "echo \"New QEMU PID: $!\"\n",
      "duration": 0.5
    },
    {
      "keystrokes": "sleep 5 && echo 'screendump /tmp/vm-screen4.ppm' | socat - UNIX-CONNECT:/tmp/qemu-monitor.sock\n",
      "duration": 10.0
